// Map page keys to their URL paths
const pagePaths: Record<keyof typeof pageSEO, string> = {
  home: '',
  studentRegister: 'student-register',
  teacherRegister: 'teacher-register',
  pricing: 'pricing',
  faq: 'faq',
  contact: 'contact',
  studentLogin: 'student-login',
  teacherLogin: 'teacher-login',
  login: 'login',
};

export const generateMetadata = (page: keyof typeof pageSEO) => {
  const seo = pageSEO[page];
  const fullTitle = seo.title;
  const path = pagePaths[page];
  const fullUrl = `${siteConfig.url}${path ? `/${path}` : ''}`;

  return {
    title: fullTitle,
    description: seo.description,
    keywords: seo.keywords,
    openGraph: {
      title: fullTitle,
      description: seo.description,
      url: fullUrl,
      siteName: siteConfig.name,
      images: [
        {
          url: siteConfig.ogImage,
          width: 1200,
          height: 630,
          alt: siteConfig.name,
        },
      ],
      locale: siteConfig.locale,
      type: 'website',
    },
    twitter: {
      card: 'summary_large_image',
      title: fullTitle,
      description: seo.description,
      images: [siteConfig.ogImage],
      creator: siteConfig.twitterHandle,
    },
    alternates: {
      canonical: fullUrl,
    },
  };
};

// Generate LocalBusiness Schema for better local SEO
export const generateLocalBusinessSchema = () => {
  return {
    '@context': 'https://schema.org',
    '@type': 'LocalBusiness',
    '@id': `${siteConfig.url}#organization`,
    name: siteConfig.name,
    description: siteConfig.description,
    url: siteConfig.url,
    logo: siteConfig.logo,
    image: siteConfig.ogImage,
    telephone: siteConfig.contact.phones,
    email: siteConfig.contact.email,
    address: {
      '@type': 'PostalAddress',
      addressLocality: siteConfig.location.city,
      addressRegion: siteConfig.location.state,
      addressCountry: siteConfig.location.country,
    },
    geo: {
      '@type': 'GeoCoordinates',
      latitude: siteConfig.location.latitude,
      longitude: siteConfig.location.longitude,
    },
    areaServed: {
      '@type': 'City',
      name: siteConfig.location.city,
      sameAs: 'https://en.wikipedia.org/wiki/Jodhpur',
    },
    openingHoursSpecification: siteConfig.businessHours.map(hours => ({
      '@type': 'OpeningHoursSpecification',
      dayOfWeek: hours.day,
      opens: hours.opens,
      closes: hours.closes,
    })),
    priceRange: '₹₹',
    aggregateRating: {
      '@type': 'AggregateRating',
      ratingValue: '4.8',
      reviewCount: '125',
      bestRating: '5',
      worstRating: '1',
    },
  };
};

// Generate FAQ Schema for FAQ page
export const generateFAQSchema = (faqs: Array<{ question: string; answer: string }>) => {
  return {
    '@context': 'https://schema.org',
    '@type': 'FAQPage',
    mainEntity: faqs.map(faq => ({
      '@type': 'Question',
      name: faq.question,
      acceptedAnswer: {
        '@type': 'Answer',
        text: faq.answer,
      },
    })),
  };
};

// Generate Breadcrumb Schema
export const generateBreadcrumbSchema = (breadcrumbs: Array<{ name: string; url: string }>) => {
  return {
    '@context': 'https://schema.org',
    '@type': 'BreadcrumbList',
    itemListElement: breadcrumbs.map((item, index) => ({
      '@type': 'ListItem',
      position: index + 1,
      name: item.name,
      item: item.url,
    })),
  };
};

// Generate Review Schema
export const generateReviewSchema = (reviews: Array<{
  author: string;
  rating: number;
  text: string;
  date: string;
}>) => {
  return reviews.map(review => ({
    '@context': 'https://schema.org',
    '@type': 'Review',
    author: {
      '@type': 'Person',
      name: review.author,
    },
    reviewRating: {
      '@type': 'Rating',
      ratingValue: review.rating,
      bestRating: '5',
      worstRating: '1',
    },
    reviewBody: review.text,
    datePublished: review.date,
  }));
};


